const amqp = require('amqplib');
const { Client } = require('pg'); // Assuming PostgreSQL for database queries

const QUEUE_NAME = 'your_queue_name';
const RABBITMQ_URL = 'amqp://localhost'; // Update with your RabbitMQ URL
const DB_CONFIG = {
  user: 'your_db_user',
  host: 'localhost',
  database: 'your_db_name',
  password: 'your_db_password',
  port: 5432,
};

const client = new Client(DB_CONFIG);

async function connectToRabbitMQ() {
  const connection = await amqp.connect(RABBITMQ_URL);
  const channel = await connection.createChannel();
  await channel.assertQueue(QUEUE_NAME, { durable: true });
  console.log(`Waiting for messages in ${QUEUE_NAME}...`);
  
  channel.consume(QUEUE_NAME, async (msg) => {
    if (msg !== null) {
      const messageContent = msg.content.toString();
      try {
        const message = JSON.parse(messageContent);
        await processMessage(message);
      } catch (error) {
        console.error('Error processing message:', error);
      } finally {
        channel.ack(msg);
      }
    }
  });
}

async function processMessage(message) {
  if (!message.type || !message.payload) {
    throw new Error('Invalid message format');
  }

  switch (message.type) {
    case 'db_query':
      await executeDatabaseQuery(message.payload);
      break;
    case 'system_command':
      await executeSystemCommand(message.payload);
      break;
    default:
      console.warn('Unknown message type:', message.type);
  }
}

async function executeDatabaseQuery(payload) {
  const query = 'SELECT * FROM your_table WHERE id = $1'; // Example query
  const values = [payload.id]; // Ensure payload.id is sanitized and validated
  const res = await client.query(query, values);
  console.log('Database query result:', res.rows);
}

async function executeSystemCommand(payload) {
  const command = `your_command ${payload.argument}`; // Ensure payload.argument is sanitized
  const { exec } = require('child_process');
  exec(command, (error, stdout, stderr) => {
    if (error) {
      console.error(`Error executing command: ${error.message}`);
      return;
    }
    if (stderr) {
      console.error(`Command stderr: ${stderr}`);
      return;
    }
    console.log(`Command output: ${stdout}`);
  });
}

async function start() {
  await client.connect();
  await connectToRabbitMQ();
}

start().catch(console.error);